import type {
  ButtonHTMLAttributes,
  CSSProperties,
  FocusEvent,
  KeyboardEvent,
  MouseEvent,
  PointerEvent,
  ReactNode,
} from "react";
import { forwardRef, useCallback, useRef, useState } from "react";
import "./Button.module.css";

export type ButtonVariant =
  | "solid"
  | "bordered"
  | "light"
  | "flat"
  | "faded"
  | "shadow"
  | "ghost";

export type ButtonColor =
  | "default"
  | "primary"
  | "secondary"
  | "info"
  | "success"
  | "warning"
  | "danger";

export type ButtonSize = "sm" | "md" | "lg";

export type ButtonRadius = "none" | "sm" | "md" | "lg" | "full";

export type PressEvent =
  | MouseEvent<HTMLButtonElement>
  | PointerEvent<HTMLButtonElement>
  | KeyboardEvent<HTMLButtonElement>
  | FocusEvent<HTMLButtonElement>;

export type ButtonProps = Omit<
  ButtonHTMLAttributes<HTMLButtonElement>,
  "color" | "children"
> & {
  children?: ReactNode;
  variant?: ButtonVariant;
  color?: ButtonColor;
  size?: ButtonSize;
  radius?: ButtonRadius;
  startContent?: ReactNode;
  endContent?: ReactNode;
  spinner?: ReactNode;
  spinnerPlacement?: "start" | "end";
  fullWidth?: boolean;
  isIconOnly?: boolean;
  isDisabled?: boolean;
  isLoading?: boolean;
  onPress?: (e: PressEvent) => void;
  onPressStart?: (e: PressEvent) => void;
  onPressEnd?: (e: PressEvent) => void;
  onPressChange?: (isPressed: boolean) => void;
  onPressUp?: (e: PressEvent) => void;
  disableRipple?: boolean;
  disableAnimation?: boolean;
  style?: CSSProperties;
};

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

type ButtonRipple = {
  id: string;
  x: number;
  y: number;
  size: number;
};

function getColorVar(color: string, depth: number) {
  const fallback = `var(--oks-color-default-${depth}, var(--oks-color-primary-${depth}, #3b82f6))`;
  if (color === "default") return fallback;
  return `var(--oks-color-${color}-${depth}, ${fallback})`;
}

export const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  (props, ref) => {
    const {
      children,
      variant = "solid",
      size = "md",
      color = "default",
      radius = "md",
      startContent,
      endContent,
      spinner,
      spinnerPlacement = "start",
      fullWidth = false,
      isIconOnly = false,
      isDisabled = false,
      isLoading = false,
      disableRipple = false,
      disableAnimation = false,
      className,
      type = "button",
      style,
      disabled: nativeDisabled,
      onMouseDown,
      onPointerDown,
      onPointerEnter,
      onPointerLeave,
      onPointerUp,
      onPointerCancel,
      onClick,
      onKeyDown,
      onKeyUp: onKeyUpProp,
      onPress,
      onPressStart,
      onPressEnd,
      onPressChange,
      onPressUp,
      onFocus,
      onBlur,
      ...rest
    } = props;

    const disabled = nativeDisabled || isDisabled;
    const [ripples, setRipples] = useState<ButtonRipple[]>([]);
    const skipMouseRippleRef = useRef(false);

    const ariaLabel = rest["aria-label"];
    const ariaLabelledBy = rest["aria-labelledby"];
    const computedAriaLabel = typeof ariaLabel === "string" ? ariaLabel : undefined;

    const nodeEnv = (globalThis as any)?.process?.env?.NODE_ENV;
    if (nodeEnv !== "production") {
      if (isIconOnly && !computedAriaLabel && typeof ariaLabelledBy !== "string") {
        throw new Error(
          "oks-ui Button: `aria-label` is required when `isIconOnly` is true.",
        );
      }
    }

    const toneVars: CSSProperties = {
      "--oks-button-tone": getColorVar(color, 500),
      "--oks-button-tone-hover": getColorVar(color, 600),
      "--oks-button-tone-active": getColorVar(color, 700),
      "--oks-button-tone-50": getColorVar(color, 50),
      "--oks-button-tone-100": getColorVar(color, 100),
      "--oks-button-tone-700": getColorVar(color, 700),
    } as unknown as CSSProperties;

    const getRippleId = () => {
      const uuid = (globalThis as any)?.crypto?.randomUUID?.();
      return typeof uuid === "string" ? uuid : `${Date.now()}-${Math.random()}`;
    };

    const isReducedMotion =
      typeof globalThis.matchMedia === "function" &&
      globalThis.matchMedia("(prefers-reduced-motion: reduce)")?.matches;

    const [isHovered, setIsHovered] = useState(false);
    const [isFocused, setIsFocused] = useState(false);
    const [isFocusVisible, setIsFocusVisible] = useState(false);
    const [isPressed, setIsPressed] = useState(false);

    const startPress = (e: PressEvent) => {
      if (disabled || isLoading) return;
      if (!isPressed) {
        onPressStart?.(e);
        onPressChange?.(true);
      }
      setIsPressed(true);
    };

    const endPress = (e: PressEvent) => {
      if (isPressed) {
        onPressEnd?.(e);
        onPressChange?.(false);
      }
      setIsPressed(false);
    };

    const createRipple = useCallback(
      (button: HTMLButtonElement, x: number, y: number) => {
        if (disableAnimation || isReducedMotion) return;

        const rect = button.getBoundingClientRect();
        const maxX = Math.max(x, rect.width - x);
        const maxY = Math.max(y, rect.height - y);
        const size = Math.ceil(Math.sqrt(maxX * maxX + maxY * maxY) * 2);

        const id = getRippleId();
        setRipples((prev) => {
          const next = [...prev, { id, x, y, size }];
          if (next.length > 10) next.splice(0, next.length - 10);
          return next;
        });
      },
      [disableAnimation, isReducedMotion],
    );

    const removeRipple = useCallback((id: string) => {
      setRipples((prev) => prev.filter((r) => r.id !== id));
    }, []);

    const handlePointerDown = (e: PointerEvent<HTMLButtonElement>) => {
      startPress(e);
      if (!disabled && !isLoading && !disableRipple) {
        skipMouseRippleRef.current = true;
        globalThis.setTimeout(() => {
          skipMouseRippleRef.current = false;
        }, 0);

        const button = e.currentTarget;
        const rect = button.getBoundingClientRect();
        if (typeof e.clientX === "number" && typeof e.clientY === "number") {
          const x = e.clientX - rect.left;
          const y = e.clientY - rect.top;
          createRipple(button, x, y);
        }
      }
      onPointerDown?.(e);
    };

    const handleMouseDown = (e: MouseEvent<HTMLButtonElement>) => {
      if (!disabled && !isLoading && !disableRipple) {
        if (skipMouseRippleRef.current) {
          onMouseDown?.(e);
          return;
        }
        const button = e.currentTarget;
        const rect = button.getBoundingClientRect();
        const x = e.clientX - rect.left;
        const y = e.clientY - rect.top;
        createRipple(button, x, y);
      }
      onMouseDown?.(e);
    };

    const handleKeyDown = (e: KeyboardEvent<HTMLButtonElement>) => {
      if (e.key === "Enter" || e.key === " ") startPress(e);
      if (!disabled && !isLoading && !disableRipple) {
        if (e.key === "Enter" || e.key === " ") {
          const button = e.currentTarget;
          const rect = button.getBoundingClientRect();
          createRipple(button, rect.width / 2, rect.height / 2);
        }
      }
      onKeyDown?.(e);
    };

    const handleKeyUp = (e: KeyboardEvent<HTMLButtonElement>) => {
      if (e.key === "Enter" || e.key === " ") {
        if (!disabled && !isLoading) onPressUp?.(e);
        endPress(e);
      }
      onKeyUpProp?.(e);
    };

    const handleClick = (e: MouseEvent<HTMLButtonElement>) => {
      if (disabled || isLoading) {
        e.preventDefault();
        e.stopPropagation();
        return;
      }
      onPress?.(e);
      onClick?.(e);
    };

    const handlePointerEnter = (e: PointerEvent<HTMLButtonElement>) => {
      setIsHovered(true);
      onPointerEnter?.(e);
    };

    const handlePointerLeave = (e: PointerEvent<HTMLButtonElement>) => {
      setIsHovered(false);
      endPress(e);
      onPointerLeave?.(e);
    };

    const handlePointerUp = (e: PointerEvent<HTMLButtonElement>) => {
      if (!disabled && !isLoading) onPressUp?.(e);
      endPress(e);
      onPointerUp?.(e);
    };

    const handlePointerCancel = (e: PointerEvent<HTMLButtonElement>) => {
      endPress(e);
      onPointerCancel?.(e);
    };

    const handleBlur = (e: any) => {
      setIsFocused(false);
      setIsFocusVisible(false);
      endPress(e);
      onBlur?.(e);
    };

    const handleFocus = (e: any) => {
      setIsFocused(true);
      const node = e?.currentTarget as HTMLElement | null;
      const focusVisible =
        typeof node?.matches === "function" ? node.matches(":focus-visible") : false;
      setIsFocusVisible(focusVisible);
      onFocus?.(e);
    };

    const defaultSpinner = (
      <span className="oksButtonSpinner" aria-hidden="true" />
    );

    const resolvedSpinner = spinner ?? defaultSpinner;
    const iconOnlyLoading = isIconOnly && isLoading;

    const buttonElement = (
      <button
        {...rest}
        aria-label={computedAriaLabel}
        ref={ref}
        type={type}
        disabled={disabled}
        onClick={handleClick}
        onMouseDown={handleMouseDown}
        onPointerDown={handlePointerDown}
        onPointerEnter={handlePointerEnter}
        onPointerLeave={handlePointerLeave}
        onPointerUp={handlePointerUp}
        onPointerCancel={handlePointerCancel}
        onKeyDown={handleKeyDown}
        onKeyUp={handleKeyUp}
        onFocus={handleFocus}
        onBlur={handleBlur}
        data-hover={isHovered ? "true" : "false"}
        data-focus={isFocused ? "true" : "false"}
        data-focus-visible={isFocusVisible ? "true" : "false"}
        data-disabled={disabled ? "true" : "false"}
        data-pressed={isPressed ? "true" : "false"}
        data-loading={isLoading ? "true" : "false"}
        data-motion={disableAnimation || isReducedMotion ? "reduced" : "default"}
        data-variant={variant}
        data-color={color}
        data-size={size}
        data-radius={radius}
        data-icon-only={isIconOnly ? "true" : "false"}
        data-full-width={fullWidth ? "true" : "false"}
        className={mergeClassName("oksButton", className)}
        style={{ ...toneVars, ...style }}
      >
        {ripples.map((ripple) => (
          <span
            key={ripple.id}
            className="oksButtonRipple"
            aria-hidden="true"
            style={{
              left: `${ripple.x}px`,
              top: `${ripple.y}px`,
              width: `${ripple.size}px`,
              height: `${ripple.size}px`,
            }}
            onAnimationEnd={() => removeRipple(ripple.id)}
          />
        ))}
        {isLoading && spinnerPlacement === "start" && !iconOnlyLoading ? (
          <span className="oksButtonSpinnerSlot" data-placement="start">
            {resolvedSpinner}
          </span>
        ) : null}
        {startContent !== undefined ? (
          <span className="oksButtonStartContent">{startContent}</span>
        ) : null}
        {iconOnlyLoading ? (
          <span className="oksButtonIconOnly" aria-hidden="true">
            {resolvedSpinner}
          </span>
        ) : isIconOnly ? (
          <span className="oksButtonIconOnly">{children}</span>
        ) : children !== undefined && children !== null ? (
          <span className="oksButtonLabel">{children}</span>
        ) : null}
        {endContent !== undefined ? (
          <span className="oksButtonEndContent">{endContent}</span>
        ) : null}
        {isLoading && spinnerPlacement === "end" && !iconOnlyLoading ? (
          <span className="oksButtonSpinnerSlot" data-placement="end">
            {resolvedSpinner}
          </span>
        ) : null}
      </button>
    );

    return buttonElement;
  },
);

Button.displayName = "Button";
