import type {
  KeyboardEvent,
  MouseEvent,
  ReactNode,
  Ref,
  ButtonHTMLAttributes,
} from "react";
import { forwardRef, useCallback, useEffect, useMemo, useRef, useState } from "react";
import type { TabsInternalItem, TabsLegacyProps } from "./Tabs.types";
import "./Tabs.module.css";

function slugify(input: string) {
  return input
    .toLowerCase()
    .trim()
    .replace(/\s+/g, "-")
    .replace(/[^a-z0-9\-]/g, "");
}

function isBrowser() {
  return typeof window !== "undefined" && typeof document !== "undefined";
}

function useURLParam(key?: string) {
  const get = useCallback((): string | null => {
    if (!isBrowser() || !key) return null;
    const url = new URL(window.location.href);
    return url.searchParams.get(key);
  }, [key]);

  const set = useCallback(
    (value?: string | null) => {
      if (!isBrowser() || !key) return;
      const url = new URL(window.location.href);
      const params = url.searchParams;
      if (value === undefined || value === null || value === "") {
        params.delete(key);
      } else {
        params.set(key, value);
      }
      const next = `${url.pathname}?${params.toString()}${url.hash ?? ""}`;
      window.history.pushState({}, "", next);
      const evt = new PopStateEvent("popstate");
      window.dispatchEvent(evt);
    },
    [key],
  );

  const subscribe = useCallback(
    (cb: (val: string | null) => void) => {
      if (!isBrowser() || !key) return () => {};
      const handler = () => cb(get());
      window.addEventListener("popstate", handler);
      return () => window.removeEventListener("popstate", handler);
    },
    [get, key],
  );

  return { get, set, subscribe };
}

function mergeButtonProps(
  base: Partial<ButtonHTMLAttributes<HTMLButtonElement>> | undefined,
  overrides: Partial<ButtonHTMLAttributes<HTMLButtonElement>> | undefined,
) {
  return { ...(base ?? {}), ...(overrides ?? {}) };
}

export const TabsLegacy = forwardRef<HTMLDivElement, TabsLegacyProps>(function TabsLegacy(
  props,
  ref: Ref<HTMLDivElement>,
) {
  const {
    data,
    defaultTab = 0,
    value,
    onChange,
    className,
    orientation = "horizontal",
    tablistPosition = "start",
    mode = "basic",
    tabId = "tab",
    variant,
    size,
    radius,
    triggerProps,
    activeTriggerProps,
    allowKeyboardNavigation = true,
    renderLazy = true,
    idStrategy,
  } = props;

  const items: TabsInternalItem[] = useMemo(
    () =>
      data.map((it) => ({
        ...it,
        id: it.id ?? (idStrategy ? idStrategy(it.title) : slugify(it.title)),
      })),
    [data, idStrategy],
  );

  const url = useURLParam(mode === "url" ? tabId : undefined);

  const findDefault = useCallback(
    (idx: number) => {
      if (idx >= 0 && idx < items.length) return idx;
      return 0;
    },
    [items.length],
  );

  const indexFromParam = useCallback((): number | null => {
    if (mode !== "url") return null;
    const val = url.get();
    if (!val) return null;
    const idx = items.findIndex((it) => it.id === val);
    return idx >= 0 ? idx : null;
  }, [items, mode, url]);

  const initialIndex = useMemo(() => {
    const fromUrl = indexFromParam();
    if (fromUrl !== null) return fromUrl;
    return findDefault(defaultTab);
  }, [defaultTab, findDefault, indexFromParam]);

  const isControlled = typeof value === "number";
  const [internalIndex, setInternalIndex] = useState<number>(initialIndex);
  const activeIndex = isControlled ? (value as number) : internalIndex;

  useEffect(() => {
    if (mode !== "url") return;
    const unsub = url.subscribe((val) => {
      const idx = val ? items.findIndex((it) => it.id === val) : -1;
      if (idx >= 0) {
        if (!isControlled) setInternalIndex(idx);
        onChange?.(idx);
      } else {
        const fallback = findDefault(defaultTab);
        if (!isControlled) setInternalIndex(fallback);
        onChange?.(fallback);
      }
    });
    return unsub;
  }, [defaultTab, findDefault, isControlled, items, mode, onChange, url]);

  const rootClass = ["oksTabsRoot", className].filter(Boolean).join(" ");

  const triggerRefs = useRef<Array<HTMLButtonElement | null>>([]);
  triggerRefs.current = [];

  const focusTab = (idx: number) => {
    const btn = triggerRefs.current[idx];
    btn?.focus();
  };

  const activate = (idx: number) => {
    if (!isControlled) setInternalIndex(idx);
    onChange?.(idx);
    if (mode === "url") {
      const id = items[idx]?.id;
      if (id) url.set(id);
    }
  };

  const onTriggerClick = (idx: number) => (e: MouseEvent<HTMLButtonElement>) => {
    e.preventDefault();
    activate(idx);
  };

  const onTriggerKeyDown =
    (idx: number) => (e: KeyboardEvent<HTMLButtonElement>) => {
      if (!allowKeyboardNavigation) return;
      const horiz = orientation === "horizontal";
      const key = e.key;
      if (key === "Home") {
        e.preventDefault();
        focusTab(0);
        return;
      }
      if (key === "End") {
        e.preventDefault();
        focusTab(items.length - 1);
        return;
      }
      if ((horiz && key === "ArrowRight") || (!horiz && key === "ArrowDown")) {
        e.preventDefault();
        const next = (idx + 1) % items.length;
        focusTab(next);
        return;
      }
      if ((horiz && key === "ArrowLeft") || (!horiz && key === "ArrowUp")) {
        e.preventDefault();
        const prev = (idx - 1 + items.length) % items.length;
        focusTab(prev);
        return;
      }
      if (key === "Enter" || key === " ") {
        e.preventDefault();
        activate(idx);
      }
    };

  const resolvedSize = size ?? "comfortable";
  const sizeAttr = resolvedSize === "compact" ? "sm" : "md";

  let effAppearance: "underline" | "segmented" | "pill" | "outline" | "dot" = "underline";
  let effIndicator: { height?: number | string; color?: string; glow?: boolean } = {
    height: 4,
  };
  let effOptions:
    | {
        underline?: {
          position?: "bottom" | "top";
          cap?: "square" | "round";
          offset?: number;
          widthStrategy?: "tab" | "label";
        };
        pill?: { elevated?: boolean };
        outline?: { activeEmphasis?: "stroke" | "fill" };
      }
    | undefined = { underline: { widthStrategy: "tab" } };

  const v = variant;

  if (v) {
    if (v === "underlineThick") effAppearance = "underline";
    if (v === "segmented") effAppearance = "segmented";
    if (v === "pill") effAppearance = "pill";
    if (v === "dot") effAppearance = "dot";
    if (v === "outline") effAppearance = "outline";
    if (v === "underlineThick") {
      effIndicator = { height: 4, ...effIndicator };
      effOptions = { underline: { widthStrategy: "tab" } };
    } else if (v === "outline") {
      effOptions = { outline: { activeEmphasis: "stroke" } };
    }
  }

  const mergedFor = (
    isActive: boolean,
  ): Partial<ButtonHTMLAttributes<HTMLButtonElement>> =>
    isActive ? mergeButtonProps(triggerProps, activeTriggerProps) : (triggerProps ?? {});

  const tablistRef = useRef<HTMLDivElement | null>(null);
  const indicatorRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    if (effAppearance !== "underline") return;
    const list = tablistRef.current;
    const ind = indicatorRef.current;
    const trg = triggerRefs.current[activeIndex];
    if (!list || !ind || !trg) return;
    const listRect = list.getBoundingClientRect();
    const trgRect = trg.getBoundingClientRect();
    if (orientation === "horizontal") {
      const x = Math.max(0, trgRect.left - listRect.left);
      const w = trgRect.width;
      const hVal =
        typeof effIndicator?.height === "number"
          ? `${effIndicator?.height}px`
          : effIndicator?.height ?? "2px";
      ind.style.setProperty("--oks-tabs-indicator-x", `${x}px`);
      ind.style.setProperty("--oks-tabs-indicator-w", `${w}px`);
      ind.style.setProperty("--oks-tabs-indicator-h", hVal);
      if (effIndicator?.color) {
        ind.style.setProperty("--oks-tabs-indicator-color", effIndicator.color);
      }
    } else {
      const y = Math.max(0, trgRect.top - listRect.top);
      const h = trgRect.height;
      const wVal =
        typeof effIndicator?.height === "number"
          ? `${effIndicator?.height}px`
          : effIndicator?.height ?? "2px";
      ind.style.setProperty("--oks-tabs-indicator-y", `${y}px`);
      ind.style.setProperty("--oks-tabs-indicator-h", `${h}px`);
      ind.style.setProperty("--oks-tabs-indicator-w", wVal);
      if (effIndicator?.color) {
        ind.style.setProperty("--oks-tabs-indicator-color", effIndicator.color);
      }
    }
  }, [activeIndex, effAppearance, effIndicator, orientation]);

  useEffect(() => {
    if (effAppearance !== "underline") return;
    const onResize = () => {
      const ind = indicatorRef.current;
      if (!ind) return;
      const idx = activeIndex;
      const btn = triggerRefs.current[idx];
      const list = tablistRef.current;
      if (!btn || !list) return;
      const listRect = list.getBoundingClientRect();
      const btnRect = btn.getBoundingClientRect();
      if (orientation === "horizontal") {
        const x = Math.max(0, btnRect.left - listRect.left);
        const w = btnRect.width;
        ind.style.setProperty("--oks-tabs-indicator-x", `${x}px`);
        ind.style.setProperty("--oks-tabs-indicator-w", `${w}px`);
      } else {
        const y = Math.max(0, btnRect.top - listRect.top);
        const h = btnRect.height;
        ind.style.setProperty("--oks-tabs-indicator-y", `${y}px`);
        ind.style.setProperty("--oks-tabs-indicator-h", `${h}px`);
      }
    };
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, [activeIndex, effAppearance, orientation]);

  const renderPanelContent = (node: ReactNode | (() => ReactNode)) => {
    return typeof node === "function" ? (node as () => ReactNode)() : node;
  };

  return (
    <div
      className={rootClass}
      data-orientation={orientation}
      data-tablist-position={tablistPosition}
      data-density={resolvedSize}
      style={{
        ...(radius !== undefined
          ? {
              ["--oks-tabs-radius" as any]:
                typeof radius === "number"
                  ? `${radius}px`
                  : radius === "none"
                    ? "0px"
                    : radius === "sm"
                      ? "0.25rem"
                      : radius === "md"
                        ? "0.5rem"
                        : radius === "lg"
                          ? "0.75rem"
                          : radius === "full"
                            ? "9999px"
                            : undefined,
            }
          : undefined),
      }}
      ref={ref}
    >
      <div
        className="oksTablist"
        role="tablist"
        aria-orientation={orientation}
        data-appearance={effAppearance}
        data-underline-position={effOptions?.underline?.position}
        data-outline-active={effOptions?.outline?.activeEmphasis}
        ref={tablistRef}
      >
        {effAppearance === "underline" ? (
          <div className="oksTabsIndicator" ref={indicatorRef} aria-hidden="true" />
        ) : null}
        {items.map((it, i) => {
          const active = i === activeIndex;
          const btnProps = mergedFor(active);
          const triggerId = `oks-tab-${it.id}`;
          const panelId = `oks-panel-${it.id}`;
          return (
            <button
              key={it.id}
              {...btnProps}
              ref={(node) => {
                triggerRefs.current[i] = node;
              }}
              role="tab"
              aria-selected={active}
              aria-controls={panelId}
              id={triggerId}
              tabIndex={active ? 0 : -1}
              title={it.title}
              onClick={onTriggerClick(i)}
              onKeyDown={onTriggerKeyDown(i)}
              data-active={active ? "true" : "false"}
              data-size={sizeAttr}
              data-elevated={
                effAppearance === "pill" && effOptions?.pill?.elevated && active
                  ? "true"
                  : undefined
              }
              className={["oksTabTrigger", (btnProps as any)?.className]
                .filter(Boolean)
                .join(" ")}
            >
              {it.title}
            </button>
          );
        })}
      </div>
      <div className="oksTabsPanels">
        {renderLazy ? (
          <div
            className="oksTabsPanel"
            role="tabpanel"
            id={`oks-panel-${items[activeIndex]?.id}`}
            aria-labelledby={`oks-tab-${items[activeIndex]?.id}`}
          >
            {renderPanelContent(items[activeIndex]?.content)}
          </div>
        ) : (
          items.map((it, i) => (
            <div
              key={it.id}
              className="oksTabsPanel"
              role="tabpanel"
              id={`oks-panel-${it.id}`}
              aria-labelledby={`oks-tab-${it.id}`}
              hidden={i !== activeIndex}
            >
              {renderPanelContent(it.content)}
            </div>
          ))
        )}
      </div>
    </div>
  );
});

TabsLegacy.displayName = "TabsLegacy";

export default TabsLegacy;

