import type { CSSProperties, HTMLAttributes, ReactNode } from "react";
import {
  createContext,
  isValidElement,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useReducer,
  useRef,
} from "react";
import { useReducedMotion } from "../../motion";
import { Portal } from "../../primitives";
import { CloseButton } from "../../internal/CloseButton/CloseButton";
import { StatusIcon } from "../../internal/icons/StatusIcons";
import "./Toast.module.css";

export type ToastId = number;

export type ToastType =
  | "default"
  | "info"
  | "success"
  | "warning"
  | "error"
  | "loading";

export type ToastTone =
  | "primary"
  | "info"
  | "success"
  | "warning"
  | "danger"
  | "secondary"
  | (string & {});

export type ToastPosition =
  | "top-left"
  | "top-center"
  | "top-right"
  | "bottom-left"
  | "bottom-center"
  | "bottom-right";

export type ToastPlacement = ToastPosition;

export type ToastColor =
  | "default"
  | "primary"
  | "secondary"
  | "success"
  | "warning"
  | "danger";

export type ToastSeverity = ToastColor;

export type ToastVariant = "solid" | "soft" | "outline" | "flat" | "bordered";

export type ToastRadius = "none" | "sm" | "md" | "lg" | "full";

export type ToastSlot =
  | "base"
  | "content"
  | "wrapper"
  | "title"
  | "description"
  | "icon"
  | "loadingComponent"
  | "progressTrack"
  | "progressIndicator"
  | "motionDiv"
  | "closeButton"
  | "closeIcon";

export type ToastClassNames = Partial<Record<ToastSlot, string>>;

export type ToastRegionProps = Omit<HTMLAttributes<HTMLDivElement>, "className"> & {
  classNames?: Partial<Record<"base", string>>;
};

export type ToastSize = "xs" | "xs-sm" | "sm" | "md" | "lg" | "xl";

export type ToastAction = {
  label: string;
  onClick?: () => void;
};

export type ToastOptions = {
  title?: ReactNode;
  message?: ReactNode;
  description?: ReactNode;
  type?: ToastType;
  tone?: ToastTone;
  color?: ToastColor;
  severity?: ToastSeverity;
  variant?: ToastVariant;
  radius?: ToastRadius;
  size?: ToastSize;
  position?: ToastPosition;
  placement?: ToastPlacement;
  duration?: number | null;
  timeout?: number | null;
  persistent?: boolean;
  showDurationBar?: boolean;
  shouldShowTimeoutProgress?: boolean;
  dismissible?: boolean;
  hideCloseButton?: boolean;
  action?: ToastAction;
  icon?: ReactNode;
  showIcon?: boolean;
  hideIcon?: boolean;
  endContent?: ReactNode;
  closeIcon?: ReactNode;
  loadingComponent?: ReactNode;
  promise?: Promise<unknown>;
  classNames?: ToastClassNames;
  id?: ToastId;
  onDismiss?: (id: ToastId) => void;
  className?: string;
  style?: CSSProperties;
};

export type ToastPromiseOptions<T> = {
  loading?: Omit<ToastOptions, "id">;
  success?: (value: T) => Omit<ToastOptions, "id">;
  error?: (error: unknown) => Omit<ToastOptions, "id">;
};

export type ToastProviderProps = {
  children?: ReactNode;
  position?: ToastPosition;
  placement?: ToastPlacement;
  maxToasts?: number;
  maxVisibleToasts?: number;
  defaultDuration?: number;
  container?: Element | DocumentFragment | null;
  motion?: "auto" | "reduced" | "default";
  disableAnimation?: boolean;
  toastOffset?: number;
  toastProps?: ToastOptions;
  regionProps?: ToastRegionProps;
  className?: string;
  style?: CSSProperties;
};

type ToastState = "open" | "closing";

type ToastItem = {
  id: ToastId;
  createdAt: number;
  state: ToastState;
  title?: ReactNode;
  message?: ReactNode;
  description?: ReactNode;
  type: ToastType;
  tone: ToastTone;
  variant: ToastVariant;
  radius?: ToastRadius;
  size: ToastSize;
  position: ToastPosition;
  duration: number | null;
  showDurationBar: boolean;
  dismissible: boolean;
  action?: ToastAction;
  icon?: ReactNode;
  showIcon: boolean;
  endContent?: ReactNode;
  closeIcon?: ReactNode;
  loadingComponent?: ReactNode;
  classNames?: ToastClassNames;
  onDismiss?: (id: ToastId) => void;
  className?: string;
  style?: CSSProperties;
};

type ToastShow = {
  (message?: ReactNode, options?: ToastOptions): ToastId;
  (options: ToastOptions): ToastId;
};

type ToastApi = {
  show: ToastShow;
  info: (message: ReactNode, options?: ToastOptions) => ToastId;
  success: (message: ReactNode, options?: ToastOptions) => ToastId;
  warning: (message: ReactNode, options?: ToastOptions) => ToastId;
  error: (message: ReactNode, options?: ToastOptions) => ToastId;
  update: (id: ToastId, patch: Partial<ToastOptions>) => void;
  dismiss: (id: ToastId) => void;
  dismissAll: () => void;
  promise: <T>(
    promiseOrFn: Promise<T> | (() => Promise<T>),
    options: ToastPromiseOptions<T>,
  ) => ToastId;
};

type ToastContextValue = ToastApi;

const ToastContext = createContext<ToastContextValue | null>(null);

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

function isToastOptions(value: unknown): value is ToastOptions {
  if (!value || typeof value !== "object") return false;
  if (isValidElement(value)) return false;
  const v = value as Record<string, unknown>;
  return (
    "type" in v ||
    "tone" in v ||
    "color" in v ||
    "severity" in v ||
    "variant" in v ||
    "radius" in v ||
    "size" in v ||
    "position" in v ||
    "placement" in v ||
    "duration" in v ||
    "timeout" in v ||
    "persistent" in v ||
    "dismissible" in v ||
    "hideCloseButton" in v ||
    "action" in v ||
    "title" in v ||
    "message" in v ||
    "description" in v ||
    "icon" in v ||
    "showIcon" in v ||
    "hideIcon" in v ||
    "endContent" in v ||
    "closeIcon" in v ||
    "loadingComponent" in v ||
    "promise" in v ||
    "classNames" in v ||
    "id" in v ||
    "className" in v ||
    "style" in v
  );
}

function omitUndefined<T extends Record<string, unknown>>(obj: T) {
  const out: Record<string, unknown> = {};
  for (const k in obj) {
    if (Object.prototype.hasOwnProperty.call(obj, k) && obj[k] !== undefined) {
      out[k] = obj[k];
    }
  }
  return out as { [K in keyof T]?: Exclude<T[K], undefined> };
}

function normalizeShowArgs(
  messageOrOptions?: ReactNode | ToastOptions,
  options?: ToastOptions,
): ToastOptions {
  if (isToastOptions(messageOrOptions))
    return { ...messageOrOptions, ...(options ?? {}) };
  return { message: messageOrOptions, ...(options ?? {}) };
}

function defaultToneForType(type: ToastType): ToastTone {
  if (type === "success") return "success";
  if (type === "warning") return "warning";
  if (type === "error") return "danger";
  if (type === "info") return "info";
  if (type === "loading") return "primary";
  return "primary";
}

function defaultShowIcon(type: ToastType): boolean {
  return true;
}

function toastRole(_type: ToastType): "alert" {
  return "alert";
}

function resolveVariant(variant: ToastVariant): "solid" | "soft" | "outline" {
  if (variant === "flat") return "soft";
  if (variant === "bordered") return "outline";
  return variant;
}

function resolveTypeFromColor(color?: ToastColor | ToastSeverity): ToastType {
  if (color === "success") return "success";
  if (color === "warning") return "warning";
  if (color === "danger") return "error";
  return "default";
}

function resolveToneFromColor(color?: ToastColor | ToastSeverity): ToastTone | undefined {
  if (!color || color === "default") return undefined;
  return color as unknown as ToastTone;
}

function getVariantVars(variant: ToastVariant, tone: string) {
  const v = resolveVariant(variant);
  const accent = `var(--oks-color-${tone}-600, var(--oks-color-primary-600, #2563eb))`;
  const softBg = `var(--oks-color-${tone}-50, var(--oks-color-primary-50, #eff6ff))`;
  const softFg = `var(--oks-color-${tone}-900, var(--oks-color-primary-900, #0b1220))`;

  if (v === "solid") {
    return { accent, bg: accent, fg: "white", border: accent };
  }

  if (v === "outline") {
    return { accent, bg: "transparent", fg: softFg, border: accent };
  }

  return { accent, bg: softBg, fg: softFg, border: accent };
}

type ToastReducerAction =
  | { type: "UPSERT"; item: ToastItem; maxToasts: number }
  | { type: "PATCH"; id: ToastId; patch: Partial<ToastOptions> }
  | { type: "MARK_CLOSING"; id: ToastId }
  | { type: "REMOVE"; id: ToastId }
  | { type: "MARK_ALL_CLOSING" };

function toastReducer(
  state: ToastItem[],
  action: ToastReducerAction,
): ToastItem[] {
  if (action.type === "UPSERT") {
    const next = [action.item, ...state.filter((t) => t.id !== action.item.id)];
    return next.slice(0, Math.max(1, action.maxToasts));
  }

  if (action.type === "PATCH") {
    return state.map((t) => {
      if (t.id !== action.id) return t;
      const patch = omitUndefined(
        action.patch as unknown as Record<string, unknown>,
      ) as Partial<Omit<ToastOptions, "id">>;
      const patchColor = patch.severity ?? patch.color;
      const nextType =
        patch.type ?? (patchColor !== undefined ? resolveTypeFromColor(patchColor) : t.type);
      const nextTone =
        patch.tone ??
        (patchColor !== undefined ? resolveToneFromColor(patchColor) ?? t.tone : t.tone);
      const nextVariant = patch.variant ?? t.variant;
      const nextSize = patch.size ?? t.size;
      const nextPosition = patch.placement ?? patch.position ?? t.position;

      const nextDuration =
        patch.persistent === true
          ? null
          : patch.timeout !== undefined
            ? patch.timeout
            : patch.duration !== undefined
              ? patch.duration
            : t.duration;

      const nextShowIcon =
        patch.hideIcon !== undefined
          ? !patch.hideIcon
          : patch.showIcon !== undefined
            ? patch.showIcon
            : patch.type !== undefined || patchColor !== undefined
              ? defaultShowIcon(nextType)
              : t.showIcon;

      const nextShowDurationBarWanted =
        patch.shouldShowTimeoutProgress ?? patch.showDurationBar;

      return {
        ...t,
        ...patch,
        type: nextType,
        tone: nextTone,
        variant: nextVariant,
        size: nextSize,
        position: nextPosition,
        duration: nextDuration,
        message: patch.message !== undefined ? patch.message : t.message,
        description:
          patch.description !== undefined ? patch.description : t.description,
        showDurationBar:
          Boolean(nextShowDurationBarWanted) && nextDuration != null,
        dismissible:
          patch.dismissible ??
          (patch.hideCloseButton !== undefined ? !patch.hideCloseButton : t.dismissible),
        showIcon: nextShowIcon,
        state: t.state,
      };
    });
  }

  if (action.type === "MARK_CLOSING") {
    return state.map((t) =>
      t.id === action.id ? { ...t, state: "closing", duration: null } : t,
    );
  }

  if (action.type === "MARK_ALL_CLOSING") {
    return state.map((t) => ({ ...t, state: "closing", duration: null }));
  }

  if (action.type === "REMOVE") {
    return state.filter((t) => t.id !== action.id);
  }
  return state;
}

export function useToast(): ToastContextValue {
  const ctx = useContext(ToastContext);
  if (!ctx) throw new Error("useToast must be used inside ToastProvider");
  return ctx;
}

let globalToastApi: ToastApi | null = null;

export type ToastClient = ToastShow & ToastApi;

const toastShow: ToastShow = ((
  messageOrOptions?: ReactNode | ToastOptions,
  options?: ToastOptions,
) => {
  if (!globalToastApi) {
    console.warn("Toast provider not configured");
    return -1;
  }
  return (globalToastApi.show as any)(messageOrOptions, options);
}) as ToastShow;

const toastFn: ToastShow = ((
  messageOrOptions?: ReactNode | ToastOptions,
  options?: ToastOptions,
) => toastShow(messageOrOptions as any, options)) as ToastShow;

export const toast: ToastClient = Object.assign(toastFn, {
  show: toastShow,
  info: (message: ReactNode, options?: ToastOptions) =>
    toastShow(message, { ...(options ?? {}), type: "info" }),
  success: (message: ReactNode, options?: ToastOptions) =>
    toastShow(message, { ...(options ?? {}), type: "success" }),
  warning: (message: ReactNode, options?: ToastOptions) =>
    toastShow(message, { ...(options ?? {}), type: "warning" }),
  error: (message: ReactNode, options?: ToastOptions) =>
    toastShow(message, { ...(options ?? {}), type: "error" }),
  update: (id: ToastId, patch: Partial<ToastOptions>) => {
    if (!globalToastApi) {
      console.warn("Toast provider not configured");
      return;
    }
    globalToastApi.update(id, patch);
  },
  dismiss: (id: ToastId) => {
    if (!globalToastApi) {
      console.warn("Toast provider not configured");
      return;
    }
    globalToastApi.dismiss(id);
  },
  dismissAll: () => {
    if (!globalToastApi) {
      console.warn("Toast provider not configured");
      return;
    }
    globalToastApi.dismissAll();
  },
  promise: <T,>(
    promiseOrFn: Promise<T> | (() => Promise<T>),
    options: ToastPromiseOptions<T>,
  ) => {
    if (!globalToastApi) {
      console.warn("Toast provider not configured");
      return -1;
    }
    return globalToastApi.promise(promiseOrFn, options);
  },
});

export function showToast(message: ReactNode, options?: ToastOptions): ToastId;
export function showToast(options: ToastOptions): ToastId;
export function showToast(
  messageOrOptions?: ReactNode | ToastOptions,
  options?: ToastOptions,
): ToastId {
  return toastShow(messageOrOptions as any, options);
}

export function addToast(options: ToastOptions): ToastId {
  return toastShow(options);
}

function ToastRow({
  item,
  dataMotion,
  onDismiss,
  stackIndex = 0,
}: {
  item: ToastItem;
  dataMotion: "reduced" | "default";
  onDismiss: (id: ToastId) => void;
  stackIndex?: number;
}) {
  const duration = item.duration;
  const timerId = useRef<number | null>(null);
  const startedAt = useRef<number>(0);
  const remainingMs = useRef<number>(duration ?? 0);
  const progressRef = useRef<HTMLDivElement | null>(null);
  const canShowDurationBar =
    stackIndex === 0 && item.showDurationBar && duration != null;

  const setDurationBar = useCallback(
    (ratio: number, transitionMs: number | null) => {
      const el = progressRef.current;
      if (!el) return;
      el.style.transform = `scaleX(${Math.max(0, Math.min(1, ratio))})`;
      if (dataMotion === "reduced" || transitionMs == null) {
        el.style.transition = "none";
        return;
      }
      el.style.transition = `transform ${transitionMs}ms linear`;
    },
    [dataMotion],
  );

  const startDurationBar = useCallback(
    (ms: number) => {
      if (!canShowDurationBar) return;
      setDurationBar(1, null);
      if (dataMotion === "reduced") return;
      requestAnimationFrame(() => setDurationBar(0, ms));
    },
    [canShowDurationBar, dataMotion, setDurationBar],
  );

  const clear = useCallback(() => {
    if (timerId.current != null) clearTimeout(timerId.current);
    timerId.current = null;
  }, []);

  const arm = useCallback(
    (ms: number) => {
      clear();
      if (ms <= 0) return;
      startedAt.current = Date.now();
      timerId.current = setTimeout(() => onDismiss(item.id), ms);
    },
    [clear, item.id, onDismiss],
  );

  const pause = useCallback(() => {
    if (duration == null) return;
    if (timerId.current == null) return;
    const elapsed = Date.now() - startedAt.current;
    remainingMs.current = Math.max(0, remainingMs.current - elapsed);
    clear();
    if (canShowDurationBar) {
      const ratio = duration > 0 ? remainingMs.current / duration : 0;
      setDurationBar(ratio, null);
    }
  }, [canShowDurationBar, clear, duration, setDurationBar]);

  const resume = useCallback(() => {
    if (duration == null) return;
    if (item.state !== "open") return;
    arm(remainingMs.current);
    if (canShowDurationBar) setDurationBar(0, remainingMs.current);
  }, [arm, canShowDurationBar, duration, item.state, setDurationBar]);

  useEffect(() => {
    clear();
    if (duration == null) return;
    remainingMs.current = duration;
    if (stackIndex === 0 && item.state === "open") {
      arm(duration);
      startDurationBar(duration);
    }
    return () => clear();
  }, [arm, clear, duration, item.state, stackIndex, startDurationBar]);

  useEffect(() => {
    if (item.state !== "open") clear();
  }, [clear, item.state]);

  const role = toastRole(item.type);
  const vars = getVariantVars(item.variant, item.tone);
  const resolvedVariant = resolveVariant(item.variant);
  const iconFg = resolvedVariant === "solid" ? vars.fg : vars.accent;
  const iconBg =
    resolvedVariant === "solid"
      ? `color-mix(in srgb, ${vars.fg} 14%, transparent)`
      : `color-mix(in srgb, ${vars.accent} 12%, transparent)`;

  const hasTitle = (item.title ?? null) !== null && item.title !== undefined;
  const description = item.description ?? item.message;
  const hasDescription = (description ?? null) !== null && description !== undefined;
  const dataAnimation = item.state === "closing" ? "exiting" : "entering";
  const classNames = item.classNames;

  const styleVars: CSSProperties = {
    ["--oks-toast-accent" as any]: vars.accent,
    ["--oks-toast-bg" as any]: vars.bg,
    ["--oks-toast-fg" as any]: vars.fg,
    ["--oks-toast-border" as any]: vars.border,
    ["--oks-toast-icon-fg" as any]: iconFg,
    ["--oks-toast-icon-bg" as any]: iconBg,
    ["--oks-toast-stack-index" as any]: String(stackIndex),
    ...item.style,
  };

  return (
    <div
      role={role}
      aria-atomic="true"
      data-has-title={hasTitle ? "true" : "false"}
      data-has-description={hasDescription ? "true" : "false"}
      data-animation={dataAnimation}
      data-placement={item.position}
      data-drag-value="0"
      data-motion={dataMotion}
      data-state={item.state}
      data-size={item.size}
      data-radius={item.radius ?? "md"}
      data-stack-index={String(stackIndex)}
      className={mergeClassName(
        mergeClassName(
          mergeClassName("oksToast", stackIndex > 0 ? "oksToastStacked" : ""),
          classNames?.base,
        ),
        item.className,
      )}
      style={styleVars}
      {...(stackIndex === 0
        ? {
            onMouseEnter: pause,
            onMouseLeave: resume,
            onFocusCapture: pause,
            onBlurCapture: resume,
          }
        : {})}
    >
      <div
        className={mergeClassName(
          mergeClassName("oksToastSurface", classNames?.motionDiv),
          mergeClassName(classNames?.base, item.className),
        )}
      >
        {item.type === "loading" && item.loadingComponent ? (
          <div
            className={mergeClassName("oksToastLoading", classNames?.loadingComponent)}
            aria-hidden="true"
          >
            {item.loadingComponent}
          </div>
        ) : item.showIcon ? (
          <div
            className={mergeClassName("oksToastIcon", classNames?.icon)}
            aria-hidden="true"
          >
            {item.icon ?? <StatusIcon type={item.type} />}
          </div>
        ) : null}

        <div className={mergeClassName("oksToastBody", classNames?.content)}>
          {hasTitle && (
            <div className={mergeClassName("oksToastTitle", classNames?.title)}>
              {item.title}
            </div>
          )}
          {hasDescription && (
            <div
              className={mergeClassName("oksToastMessage", classNames?.description)}
            >
              {description}
            </div>
          )}
        </div>

        {stackIndex === 0 && (item.action || item.endContent || item.dismissible) && (
          <div className={mergeClassName("oksToastControls", classNames?.wrapper)}>
            {item.action && (
              <button
                type="button"
                className="oksToastAction"
                onClick={() => item.action?.onClick?.()}
              >
                {item.action.label}
              </button>
            )}
            {item.endContent}
            {item.dismissible && (
              <CloseButton
                ariaLabel="Close"
                className={mergeClassName("oksToastClose", classNames?.closeButton)}
                {...(item.closeIcon !== undefined ? { icon: item.closeIcon } : {})}
                {...(classNames?.closeIcon !== undefined
                  ? { iconClassName: classNames.closeIcon }
                  : {})}
                onClick={() => onDismiss(item.id)}
              />
            )}
          </div>
        )}

        {canShowDurationBar && (
          <div
            className={mergeClassName(
              "oksToastProgressTrack",
              classNames?.progressTrack,
            )}
            aria-hidden="true"
          >
            <div
              ref={progressRef}
              className={mergeClassName(
                "oksToastProgressIndicator",
                classNames?.progressIndicator,
              )}
            />
          </div>
        )}
      </div>
    </div>
  );
}

export function ToastProvider({
  children,
  position,
  placement,
  maxToasts,
  maxVisibleToasts,
  defaultDuration = 6000,
  container,
  motion = "auto",
  disableAnimation,
  toastOffset = 0,
  toastProps,
  regionProps,
  className,
  style,
}: ToastProviderProps) {
  const reducedMotion = useReducedMotion();
  const resolvedPlacement: ToastPosition = placement ?? position ?? "bottom-right";
  const resolvedMaxVisible = maxVisibleToasts ?? maxToasts ?? 3;
  const resolvedQueueLimit =
    maxToasts !== undefined ? maxToasts : Math.max(resolvedMaxVisible, 12);
  const dataMotion: "reduced" | "default" =
    disableAnimation === true ||
    motion === "reduced" ||
    (motion === "auto" && reducedMotion)
      ? "reduced"
      : "default";
  const closeDelayMs = dataMotion === "reduced" ? 0 : 260;

  const idCounter = useRef(0);
  const removalTimers = useRef<Map<ToastId, number>>(new Map());

  const [items, dispatch] = useReducer(toastReducer, []);
  const itemsRef = useRef<ToastItem[]>([]);
  itemsRef.current = items;

  const scheduleRemoval = useCallback(
    (id: ToastId) => {
      const existing = removalTimers.current.get(id);
      if (existing != null) clearTimeout(existing);
      if (closeDelayMs <= 0) {
        dispatch({ type: "REMOVE", id });
        return;
      }
      const t = setTimeout(() => {
        removalTimers.current.delete(id);
        dispatch({ type: "REMOVE", id });
      }, closeDelayMs);
      removalTimers.current.set(id, t);
    },
    [closeDelayMs],
  );

  const dismiss = useCallback(
    (id: ToastId) => {
      const current = itemsRef.current.find((t) => t.id === id);
      if (current && current.state !== "closing") current.onDismiss?.(id);
      dispatch({ type: "MARK_CLOSING", id });
      scheduleRemoval(id);
    },
    [scheduleRemoval],
  );

  const dismissAll = useCallback(() => {
    const current = itemsRef.current;
    for (const t of current) {
      if (t.state !== "closing") t.onDismiss?.(t.id);
    }
    dispatch({ type: "MARK_ALL_CLOSING" });
    for (const t of current) scheduleRemoval(t.id);
  }, [scheduleRemoval]);

  const update = useCallback((id: ToastId, patch: Partial<ToastOptions>) => {
    dispatch({ type: "PATCH", id, patch });
  }, []);

  const show = useCallback(
    ((messageOrOptions?: ReactNode | ToastOptions, options?: ToastOptions) => {
      const incomingRaw = normalizeShowArgs(messageOrOptions, options);
      const incoming: ToastOptions = { ...(toastProps ?? {}), ...incomingRaw };

      const resolvedColor = incoming.severity ?? incoming.color;
      const type =
        incoming.type ?? (resolvedColor ? resolveTypeFromColor(resolvedColor) : "default");
      const tone =
        incoming.tone ??
        (resolvedColor ? resolveToneFromColor(resolvedColor) : undefined) ??
        defaultToneForType(type);
      const variant = incoming.variant ?? "flat";
      const size = incoming.size ?? "md";
      const pos = incoming.placement ?? incoming.position ?? resolvedPlacement;
      const dismissible =
        incoming.hideCloseButton !== undefined
          ? !incoming.hideCloseButton
          : (incoming.dismissible ?? true);
      const persistent = Boolean(incoming.persistent);
      const timeout = incoming.timeout ?? incoming.duration;
      const duration = persistent ? null : timeout !== undefined ? timeout : defaultDuration;
      const showDurationBar =
        Boolean(incoming.shouldShowTimeoutProgress ?? incoming.showDurationBar) &&
        duration != null;
      const showIcon =
        incoming.hideIcon !== undefined
          ? !incoming.hideIcon
          : (incoming.showIcon ?? defaultShowIcon(type));

      const id = incoming.id ?? ++idCounter.current;

      const base: ToastItem = {
        id,
        createdAt: Date.now(),
        state: "open",
        type,
        tone,
        variant,
        radius: incoming.radius ?? "md",
        size,
        position: pos,
        duration,
        showDurationBar,
        dismissible,
        showIcon,
      };
      const item: ToastItem = {
        ...base,
        ...(incoming.title !== undefined ? { title: incoming.title } : {}),
        ...(incoming.message !== undefined ? { message: incoming.message } : {}),
        ...(incoming.description !== undefined
          ? { description: incoming.description }
          : {}),
        ...(incoming.action !== undefined ? { action: incoming.action } : {}),
        ...(incoming.icon !== undefined ? { icon: incoming.icon } : {}),
        ...(incoming.endContent !== undefined
          ? { endContent: incoming.endContent }
          : {}),
        ...(incoming.closeIcon !== undefined
          ? { closeIcon: incoming.closeIcon }
          : {}),
        ...(incoming.loadingComponent !== undefined
          ? { loadingComponent: incoming.loadingComponent }
          : {}),
        ...(incoming.classNames !== undefined
          ? { classNames: incoming.classNames }
          : {}),
        ...(incoming.onDismiss !== undefined
          ? { onDismiss: incoming.onDismiss }
          : {}),
        ...(incoming.className !== undefined
          ? { className: incoming.className }
          : {}),
        ...(incoming.style !== undefined ? { style: incoming.style } : {}),
      };

      if (incoming.promise) {
        const p = incoming.promise;
        const resolvedTimeout = timeout !== undefined ? timeout : defaultDuration;
        const resolvedTimeoutProgress =
          incoming.shouldShowTimeoutProgress ?? incoming.showDurationBar;
        dispatch({
          type: "UPSERT",
          item: {
            ...item,
            type: "loading",
            duration: null,
            showDurationBar: false,
            dismissible,
          },
          maxToasts: resolvedQueueLimit,
        });
        p.then(
          () =>
            update(id, {
              type: "success",
              timeout: resolvedTimeout,
              ...(resolvedTimeoutProgress !== undefined
                ? { shouldShowTimeoutProgress: resolvedTimeoutProgress }
                : {}),
              dismissible,
            }),
          () =>
            update(id, {
              type: "error",
              timeout: resolvedTimeout,
              ...(resolvedTimeoutProgress !== undefined
                ? { shouldShowTimeoutProgress: resolvedTimeoutProgress }
                : {}),
              dismissible,
            }),
        );
        return id;
      }

      dispatch({ type: "UPSERT", item, maxToasts: resolvedQueueLimit });
      return id;
    }) as ToastShow,
    [defaultDuration, resolvedPlacement, resolvedQueueLimit, toastProps, update],
  );

  const promise = useCallback(
    <T,>(
      promiseOrFn: Promise<T> | (() => Promise<T>),
      options: ToastPromiseOptions<T>,
    ) => {
      const p = typeof promiseOrFn === "function" ? promiseOrFn() : promiseOrFn;

      const id = show({
        ...(options.loading ?? {}),
        type: options.loading?.type ?? "loading",
        persistent: true,
        dismissible: options.loading?.dismissible ?? false,
      });

      p.then(
        (value) => {
          const resolved = options.success?.(value) ?? {};
          update(id, {
            ...resolved,
            type: resolved.type ?? "success",
            persistent: false,
          });
        },
        (error) => {
          const resolved = options.error?.(error) ?? {};
          update(id, {
            ...resolved,
            type: resolved.type ?? "error",
            persistent: false,
          });
        },
      );

      return id;
    },
    [show, update],
  );

  const api = useMemo<ToastApi>(
    () => ({
      show,
      info: (message, options) =>
        show(message, { ...(options ?? {}), type: "info" }),
      success: (message, options) =>
        show(message, { ...(options ?? {}), type: "success" }),
      warning: (message, options) =>
        show(message, { ...(options ?? {}), type: "warning" }),
      error: (message, options) =>
        show(message, { ...(options ?? {}), type: "error" }),
      update,
      dismiss,
      dismissAll,
      promise,
    }),
    [dismiss, dismissAll, promise, show, update],
  );

  useEffect(() => {
    globalToastApi = api;
    return () => {
      if (globalToastApi === api) globalToastApi = null;
    };
  }, [api]);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const onKeyDown = (e: KeyboardEvent) => {
      if (e.key !== "Escape") return;
      const first = items[0];
      if (!first) return;
      dismiss(first.id);
    };
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [dismiss, items]);

  useEffect(() => {
    return () => {
      for (const t of removalTimers.current.values()) clearTimeout(t);
      removalTimers.current.clear();
    };
  }, []);

  const grouped = useMemo(() => {
    const map: Partial<Record<ToastPosition, ToastItem[]>> = {};
    for (const t of items) {
      const pos = t.position;
      const list = map[pos] ?? [];
      list.push(t);
      map[pos] = list;
    }
    return map;
  }, [items]);

  const {
    classNames: regionClassNames,
    style: regionStyle,
    ...regionDomProps
  } = regionProps ?? {};

  const viewportStyle: CSSProperties = {
    ["--oks-toast-offset" as any]: `${toastOffset}px`,
    ...(style ?? {}),
    ...(regionStyle ?? {}),
  };

  return (
    <ToastContext.Provider value={api}>
      {children}
      <Portal container={container}>
        {Object.entries(grouped).map(([posKey, list]) => {
          const pos = posKey as ToastPosition;
          const visibleCount = Math.max(1, resolvedMaxVisible);
          const visible = list.slice(0, visibleCount);
          const visual = visible;
          const overflowCount = Math.max(0, list.length - visibleCount);
          return (
            <div
              key={posKey}
              data-position={pos}
              className={mergeClassName(
                mergeClassName("oksToastViewport", regionClassNames?.base),
                className,
              )}
              style={viewportStyle}
              aria-live="polite"
              {...regionDomProps}
            >
              <div
                className="oksToastStack"
                data-position={pos}
                data-has-overflow={overflowCount > 0 ? "true" : "false"}
                data-overflow-count={String(overflowCount)}
              >
                {visual.map((t, visualIndex) => (
                  <ToastRow
                    key={t.id}
                    item={t}
                    dataMotion={dataMotion}
                    onDismiss={dismiss}
                    stackIndex={visualIndex}
                  />
                ))}
              </div>
            </div>
          );
        })}
      </Portal>
    </ToastContext.Provider>
  );
}
