import type {
  CSSProperties,
  Key,
  KeyboardEvent,
  ReactElement,
  ReactNode,
  Ref,
} from "react";
import {
  Children,
  forwardRef,
  isValidElement,
  useCallback,
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";
import { Tab } from "./Tab";
import type { TabProps, TabsProps } from "./Tabs.types";
import "./Tabs.module.css";

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

function getColorVar(color: string, depth: number) {
  const fallback = `var(--oks-color-default-${depth}, var(--oks-color-primary-${depth}, #3b82f6))`;
  if (color === "default") return fallback;
  return `var(--oks-color-${color}-${depth}, ${fallback})`;
}

type ParsedTab = {
  key: Key;
  props: TabProps;
};

function keyToIdPart(key: Key) {
  const str = String(key);
  return str
    .trim()
    .replace(/\s+/g, "-")
    .replace(/[^a-zA-Z0-9\-_:.]/g, "");
}

function isTabElement(node: unknown): node is ReactElement<TabProps> {
  return isValidElement(node) && node.type === Tab;
}

function normalizeElementKey(key: string) {
  return key.startsWith(".$") ? key.slice(2) : key;
}

function pickInitialKey(keys: Key[], disabled: Set<Key>) {
  for (const k of keys) {
    if (!disabled.has(k)) return k;
  }
  return undefined;
}

export const Tabs = forwardRef<HTMLDivElement, TabsProps>(function Tabs(
  props,
  ref: Ref<HTMLDivElement>,
) {
  const {
    children,
    variant = "solid",
    color = "default",
    size = "md",
    radius = "full",
    fullWidth = false,
    items,
    disabledKeys,
    selectedKey,
    defaultSelectedKey,
    shouldSelectOnPressUp = true,
    keyboardActivation = "automatic",
    disableCursorAnimation = false,
    isDisabled = false,
    disableAnimation = false,
    classNames,
    className,
    placement = "top",
    isVertical = false,
    destroyInactiveTabPanel = true,
    onSelectionChange,
    ...rest
  } = props;

  const disabledSet = useMemo(() => {
    const set = new Set<Key>();
    for (const k of disabledKeys ?? []) set.add(k);
    return set;
  }, [disabledKeys]);

  const renderedTabs: ParsedTab[] = useMemo(() => {
    if (items !== undefined) {
      const render = children as unknown;
      if (typeof render !== "function") return [];
      const out: ParsedTab[] = [];
      for (const item of items as Iterable<unknown>) {
        const el = (render as (it: unknown) => ReactElement)(item);
        if (!isTabElement(el)) continue;
        const k = el.key;
        if (k === null || k === undefined) continue;
        out.push({
          key: typeof k === "string" ? normalizeElementKey(k) : k,
          props: el.props,
        });
      }
      return out;
    }

    const out: ParsedTab[] = [];
    for (const node of Children.toArray(children)) {
      if (!isTabElement(node)) continue;
      const k = node.key;
      if (k === null || k === undefined) continue;
      out.push({
        key: typeof k === "string" ? normalizeElementKey(k) : k,
        props: node.props,
      });
    }
    return out;
  }, [children, items]);

  const keys = useMemo(() => renderedTabs.map((t) => t.key), [renderedTabs]);

  const nodeEnv = (globalThis as any)?.process?.env?.NODE_ENV;
  if (nodeEnv !== "production") {
    for (const t of (items !== undefined
      ? []
      : Children.toArray(children)) as unknown[]) {
      if (isTabElement(t) && (t as any).key == null) {
        throw new Error("oks-ui Tabs: each <Tab /> must have a React `key`.");
      }
    }
  }

  const controlled = selectedKey !== undefined;
  const [internalKey, setInternalKey] = useState<Key | undefined>(() => {
    if (defaultSelectedKey !== undefined) return defaultSelectedKey;
    return pickInitialKey(keys, disabledSet);
  });

  const effectiveVertical = useMemo(() => {
    if (isVertical) return true;
    return placement === "start" || placement === "end";
  }, [isVertical, placement]);

  const resolvedPlacement: "top" | "bottom" | "start" | "end" = useMemo(() => {
    if (isVertical) return "start";
    return placement;
  }, [isVertical, placement]);

  const resolvedSelectedKey = useMemo(() => {
    const current = controlled ? selectedKey : internalKey;
    if (current !== undefined && current !== null) {
      if (keys.includes(current) && !disabledSet.has(current)) return current;
    }
    return pickInitialKey(keys, disabledSet);
  }, [controlled, disabledSet, internalKey, keys, selectedKey]);

  const selectKey = useCallback(
    (k: Key) => {
      if (isDisabled) return;
      if (disabledSet.has(k)) return;
      if (!keys.includes(k)) return;
      if (!controlled) setInternalKey(k);
      onSelectionChange?.(k);
    },
    [controlled, disabledSet, isDisabled, keys, onSelectionChange],
  );

  const triggerRefs = useRef<Map<Key, HTMLElement | null>>(new Map());
  const setTriggerRef = useCallback((k: Key, node: HTMLElement | null) => {
    triggerRefs.current.set(k, node);
  }, []);

  const autoId = useId();
  const tabsId = useMemo(() => {
    const base = rest.id ? keyToIdPart(rest.id) : keyToIdPart(`tabs-${autoId}`);
    return `oks-${base}`;
  }, [autoId, rest.id]);

  const getIds = useCallback(
    (k: Key) => {
      const part = keyToIdPart(k);
      return { tab: `${tabsId}-tab-${part}`, panel: `${tabsId}-panel-${part}` };
    },
    [tabsId],
  );

  const tabListRef = useRef<HTMLDivElement | null>(null);
  const cursorRef = useRef<HTMLDivElement | null>(null);

  const positionCursor = useCallback(() => {
    if (variant !== "underlined") return;
    const list = tabListRef.current;
    const cursor = cursorRef.current;
    if (!list || !cursor) return;
    const activeKey = resolvedSelectedKey;
    if (activeKey === undefined) return;
    const el = triggerRefs.current.get(activeKey) as HTMLElement | null;
    if (!el) return;
    const listRect = list.getBoundingClientRect();
    const elRect = el.getBoundingClientRect();
    if (!effectiveVertical) {
      const x = Math.max(0, elRect.left - listRect.left);
      const w = elRect.width;
      cursor.style.setProperty("--oks-tabs-cursor-x", `${x}px`);
      cursor.style.setProperty("--oks-tabs-cursor-w", `${w}px`);
    } else {
      const y = Math.max(0, elRect.top - listRect.top);
      const h = elRect.height;
      cursor.style.setProperty("--oks-tabs-cursor-y", `${y}px`);
      cursor.style.setProperty("--oks-tabs-cursor-h", `${h}px`);
    }
  }, [effectiveVertical, resolvedSelectedKey, variant]);

  useEffect(() => {
    positionCursor();
  }, [positionCursor]);

  useEffect(() => {
    if (variant !== "underlined") return;
    const onResize = () => positionCursor();
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, [positionCursor, variant]);

  const onListKeyDown = (e: KeyboardEvent<HTMLDivElement>) => {
    if (isDisabled) return;
    const list = tabListRef.current;
    if (!list) return;

    const keysInOrder = keys;
    if (keysInOrder.length === 0) return;

    const activeEl = globalThis.document?.activeElement as HTMLElement | null;
    const focusedKey = (() => {
      for (const k of keysInOrder) {
        const node = triggerRefs.current.get(k);
        if (node && activeEl && node === activeEl) return k;
      }
      return resolvedSelectedKey;
    })();

    const focusedIndex =
      focusedKey !== undefined ? keysInOrder.indexOf(focusedKey) : -1;

    const move = (direction: 1 | -1) => {
      if (keysInOrder.length === 0) return;
      let idx = focusedIndex >= 0 ? focusedIndex : 0;
      for (let i = 0; i < keysInOrder.length; i++) {
        idx = (idx + direction + keysInOrder.length) % keysInOrder.length;
        const nextKey = keysInOrder[idx]!;
        if (disabledSet.has(nextKey)) continue;
        const node = triggerRefs.current.get(nextKey);
        node?.focus();
        if (keyboardActivation === "automatic") selectKey(nextKey);
        return;
      }
    };

    const focusEdge = (edge: "start" | "end") => {
      const ordered = edge === "start" ? keysInOrder : [...keysInOrder].reverse();
      for (const k of ordered) {
        if (disabledSet.has(k)) continue;
        const node = triggerRefs.current.get(k);
        node?.focus();
        if (keyboardActivation === "automatic") selectKey(k);
        return;
      }
    };

    const horiz = !effectiveVertical;
    const key = e.key;

    if (key === "Home") {
      e.preventDefault();
      focusEdge("start");
      return;
    }
    if (key === "End") {
      e.preventDefault();
      focusEdge("end");
      return;
    }
    if (
      (horiz && key === "ArrowRight") ||
      (!horiz && key === "ArrowDown")
    ) {
      e.preventDefault();
      move(1);
      return;
    }
    if (
      (horiz && key === "ArrowLeft") ||
      (!horiz && key === "ArrowUp")
    ) {
      e.preventDefault();
      move(-1);
      return;
    }
    if (keyboardActivation === "manual" && (key === "Enter" || key === " ")) {
      if (!activeEl) return;
      for (const k of keysInOrder) {
        const node = triggerRefs.current.get(k);
        if (node && node === activeEl) {
          e.preventDefault();
          selectKey(k);
          return;
        }
      }
    }
  };

  const baseClassName = mergeClassName(
    mergeClassName("oksTabsRoot", classNames?.base),
    className,
  );
  const tabListClassName = mergeClassName("oksTablist", classNames?.tabList);
  const cursorClassName = mergeClassName("oksTabsCursor", classNames?.cursor);
  const panelsClassName = "oksTabsPanels";
  const panelClassName = mergeClassName("oksTabsPanel", classNames?.panel);

  const toneVars: CSSProperties = {
    ["--oks-tabs-tone" as any]: getColorVar(color, 500),
    ["--oks-tabs-tone-50" as any]: getColorVar(color, 50),
    ["--oks-tabs-tone-700" as any]: getColorVar(color, 700),
  } as unknown as CSSProperties;

  const baseStyle: CSSProperties = {
    ...toneVars,
    ...(rest.style ?? {}),
  };

  const activeTab = useMemo(() => {
    if (resolvedSelectedKey === undefined) return undefined;
    return renderedTabs.find((t) => t.key === resolvedSelectedKey);
  }, [renderedTabs, resolvedSelectedKey]);

  return (
    <div
      {...rest}
      ref={ref}
      className={baseClassName}
      style={baseStyle}
      data-variant={variant}
      data-color={color}
      data-size={size}
      data-radius={radius}
      data-full-width={fullWidth ? "true" : "false"}
      data-placement={resolvedPlacement}
      data-vertical={effectiveVertical ? "true" : "false"}
      data-disabled={isDisabled ? "true" : "false"}
      data-motion={disableAnimation ? "reduced" : "default"}
      data-disable-cursor-animation={disableCursorAnimation ? "true" : "false"}
    >
      <div
        className={tabListClassName}
        role="tablist"
        aria-orientation={effectiveVertical ? "vertical" : "horizontal"}
        ref={tabListRef}
        onKeyDown={onListKeyDown}
      >
        {variant === "underlined" ? (
          <div
            className={cursorClassName}
            ref={cursorRef}
            aria-hidden="true"
          />
        ) : null}
        {renderedTabs.map((t) => {
          const selected = t.key === resolvedSelectedKey;
          const disabled = isDisabled || disabledSet.has(t.key);
          const ids = getIds(t.key);
          const tabWrapperClassName = mergeClassName(
            "oksTabsTabWrapper",
            classNames?.tabWrapper,
          );
          const tabClassName = mergeClassName("oksTabsTab", classNames?.tab);
          const tabContentClassName = mergeClassName(
            "oksTabsTabContent",
            classNames?.tabContent,
          );

          const effectivePressUp =
            t.props.shouldSelectOnPressUp ?? shouldSelectOnPressUp;

          const onSelect = () => selectKey(t.key);

          const setExternalRef = (node: HTMLElement | null) => {
            setTriggerRef(t.key, node);
            if (t.props.tabRef) (t.props.tabRef as any).current = node;
          };

          const commonProps = {
            role: "tab" as const,
            id: ids.tab,
            "aria-selected": selected,
            "aria-controls": ids.panel,
            tabIndex: selected ? 0 : -1,
            "data-selected": selected ? "true" : undefined,
            "data-disabled": disabled ? "true" : undefined,
          };

          const content = (
            <span className={tabContentClassName}>{t.props.title}</span>
          );

          return (
            <div key={String(t.key)} className={tabWrapperClassName}>
              {t.props.href ? (
                <a
                  {...commonProps}
                  className={tabClassName}
                  href={t.props.href}
                  target={t.props.target}
                  rel={t.props.rel}
                  download={t.props.download as any}
                  ping={t.props.ping}
                  referrerPolicy={t.props.referrerPolicy}
                  aria-disabled={disabled ? "true" : undefined}
                  onClick={
                    disabled
                      ? (e) => {
                          e.preventDefault();
                        }
                      : effectivePressUp
                        ? () => onSelect()
                        : undefined
                  }
                  onMouseDown={
                    disabled
                      ? undefined
                      : effectivePressUp
                        ? undefined
                        : (e) => {
                            e.preventDefault();
                            onSelect();
                          }
                  }
                  ref={setExternalRef as any}
                >
                  {content}
                </a>
              ) : (
                <button
                  {...commonProps}
                  type="button"
                  className={tabClassName}
                  disabled={disabled}
                  onClick={effectivePressUp ? onSelect : undefined}
                  onMouseDown={
                    effectivePressUp
                      ? undefined
                      : (e) => {
                          e.preventDefault();
                          onSelect();
                        }
                  }
                  ref={setExternalRef as any}
                >
                  {content}
                </button>
              )}
            </div>
          );
        })}
      </div>
      <div className={panelsClassName}>
        {destroyInactiveTabPanel ? (
          activeTab ? (
            <div
              className={panelClassName}
              role="tabpanel"
              id={getIds(activeTab.key).panel}
              aria-labelledby={getIds(activeTab.key).tab}
            >
              {activeTab.props.children}
            </div>
          ) : null
        ) : (
          renderedTabs.map((t) => {
            const selected = t.key === resolvedSelectedKey;
            const ids = getIds(t.key);
            return (
              <div
                key={String(t.key)}
                className={panelClassName}
                role="tabpanel"
                id={ids.panel}
                aria-labelledby={ids.tab}
                hidden={!selected}
              >
                {t.props.children}
              </div>
            );
          })
        )}
      </div>
    </div>
  );
});

Tabs.displayName = "Tabs";

export default Tabs;
