import { forwardRef } from "react";
import type { Ref, ReactNode } from "react";
import { useTabsContext } from "./context";
import "./Tabs.module.css";

export type TabTriggerProps = {
  value: string | number;
  disabled?: boolean;
  className?: string;
  children?: ReactNode;
};

export const TabTrigger = forwardRef<HTMLButtonElement, TabTriggerProps>(
  function TabTrigger(props, ref: Ref<HTMLButtonElement>) {
    const { value, disabled, className, children } = props;
    const ctx = useTabsContext();
    const active = ctx.isActive(value);
    const ids = ctx.getIds(value);
    const sizeAttr = ctx.density === "compact" ? "sm" : "md";
    const cls = ["oksTabTrigger", className].filter(Boolean).join(" ");
    return (
      <button
        ref={ref}
        className={cls}
        role="tab"
        id={ids.tab}
        aria-selected={active}
        aria-controls={ids.panel}
        tabIndex={active ? 0 : -1}
        disabled={disabled}
        data-active={active ? "true" : "false"}
        data-size={sizeAttr}
        data-elevated={
          ctx.appearance === "pill" && ctx.appearanceOptions?.pill?.elevated && active
            ? "true"
            : undefined
        }
        onClick={() => ctx.setValue(value)}
      >
        <span className="oksTabLabel">{children}</span>
      </button>
    );
  },
);

TabTrigger.displayName = "TabTrigger";

