import type { CSSProperties, HTMLAttributes, ReactNode } from "react";
import { forwardRef } from "react";
import "./Badge.module.css";

export type BadgeVariant =
  | "solid"
  | "bordered"
  | "light"
  | "flat"
  | "faded"
  | "shadow"
  | "ghost";

export type BadgeSize = "sm" | "md" | "lg";

export type BadgeColor =
  | "default"
  | "primary"
  | "secondary"
  | "info"
  | "success"
  | "warning"
  | "danger";

export type BadgePlacement =
  | "top-right"
  | "top-left"
  | "bottom-right"
  | "bottom-left";

export type BadgeShape = "circle" | "rectangle";

export type BadgeSlot = "base" | "badge";

export type BadgeProps = Omit<
  HTMLAttributes<HTMLSpanElement>,
  "color" | "children"
> & {
  children?: ReactNode;
  content?: string | number | ReactNode;
  max?: number;
  variant?: BadgeVariant;
  color?: BadgeColor;
  size?: BadgeSize;
  shape?: BadgeShape;
  placement?: BadgePlacement;
  showOutline?: boolean;
  disableOutline?: boolean;
  disableAnimation?: boolean;
  isInvisible?: boolean;
  isOneChar?: boolean;
  isDot?: boolean;
  classNames?: Partial<Record<BadgeSlot, string>>;
  style?: CSSProperties;
};

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

function getColorVar(color: string, depth: number) {
  const fallback = `var(--oks-color-default-${depth}, var(--oks-color-primary-${depth}, #3b82f6))`;
  if (color === "default") return fallback;
  return `var(--oks-color-${color}-${depth}, ${fallback})`;
}

export const Badge = forwardRef<HTMLSpanElement, BadgeProps>((props, ref) => {
  const {
    children,
    content,
    max,
    variant = "solid",
    color = "default",
    size = "md",
    shape = "rectangle",
    placement = "top-right",
    showOutline = true,
    disableOutline = false,
    disableAnimation = false,
    isInvisible = false,
    isOneChar = false,
    isDot = false,
    classNames,
    className,
    style,
    ...rest
  } = props;

  const resolvedOutline = disableOutline ? false : showOutline;
  const hasContent = content !== undefined && content !== null;
  const shouldRenderBadge = !isInvisible && (isDot || hasContent);

  const resolvedMax =
    typeof max === "number" && Number.isFinite(max) && max > 0
      ? Math.floor(max)
      : undefined;

  const displayContent =
    !isDot &&
    typeof content === "number" &&
    resolvedMax !== undefined &&
    content > resolvedMax
      ? `${resolvedMax}+`
      : content;

  const toneVars: CSSProperties = {
    "--oks-badge-tone": getColorVar(color, 500),
    "--oks-badge-tone-50": getColorVar(color, 50),
    "--oks-badge-tone-100": getColorVar(color, 100),
    "--oks-badge-tone-700": getColorVar(color, 700),
    "--oks-badge-solid-fg": "#fff",
  } as unknown as CSSProperties;

  const badgeEl = shouldRenderBadge ? (
    <span className={mergeClassName("oksBadgeBadge", classNames?.badge)}>
      {isDot ? null : displayContent}
    </span>
  ) : null;

  return (
    <span
      {...rest}
      ref={ref}
      data-variant={variant}
      data-color={color}
      data-size={size}
      data-shape={shape}
      data-placement={placement}
      data-outline={resolvedOutline ? "true" : "false"}
      data-dot={isDot ? "true" : "false"}
      data-one-char={isOneChar ? "true" : "false"}
      data-invisible={isInvisible ? "true" : "false"}
      data-disable-animation={disableAnimation ? "true" : "false"}
      className={mergeClassName(
        mergeClassName("oksBadge", classNames?.base),
        className,
      )}
      style={{ ...toneVars, ...style }}
    >
      {children}
      {badgeEl}
    </span>
  );
});

Badge.displayName = "Badge";
