import type { CSSProperties, ReactNode, RefObject } from "react";
import { useEffect, useId, useMemo, useRef } from "react";
import type { BackdropProps } from "../Backdrop";
import { Backdrop } from "../Backdrop";
import type { PageTitleProps } from "../PageTitle";
import { PageTitle } from "../PageTitle";
import { CloseButton } from "../../internal/CloseButton/CloseButton";
import "./Drawer.module.css";

export type DrawerPosition = "left" | "right" | "top" | "bottom";

export type DrawerSize = "sm" | "md" | "lg" | (string & {}) | number;

export type DrawerProps = {
  isOpen: boolean;
  onClose: () => void;
  position?: DrawerPosition;
  title?: ReactNode;
  children?: ReactNode;
  actions?: ReactNode;
  dismissible?: boolean;
  closeLabel?: string;
  ariaLabel?: string;
  width?: DrawerSize;
  height?: DrawerSize;
  closeOnOutsideClick?: boolean;
  closeOnEscape?: boolean;
  portal?: boolean;
  container?: Element | DocumentFragment | null;
  zIndex?: number;
  blur?: boolean;
  backgroundOpacity?: number;
  animationDuration?: number;
  easing?: BackdropProps["easing"];
  initialFocusRef?: RefObject<HTMLElement | null>;
  backdrop?: Omit<Partial<BackdropProps>, "isOpen" | "onClose" | "children">;
  headers?: Partial<PageTitleProps>;
  className?: string;
  style?: CSSProperties;
};

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

function resolveWidth(size: DrawerSize | undefined) {
  if (typeof size === "number") return `${size}px`;
  if (size === "sm") return "360px";
  if (size === "md") return "420px";
  if (size === "lg") return "520px";
  if (typeof size === "string") return size;
  return "420px";
}

function resolveHeight(size: DrawerSize | undefined) {
  if (typeof size === "number") return `${size}px`;
  if (size === "sm") return "280px";
  if (size === "md") return "360px";
  if (size === "lg") return "480px";
  if (typeof size === "string") return size;
  return "360px";
}

function resolveAnimationType(
  position: DrawerPosition,
): NonNullable<BackdropProps["animationType"]> {
  if (position === "left") return "slideRight";
  if (position === "right") return "slideLeft";
  if (position === "top") return "slideDown";
  return "slideUp";
}

export function Drawer(props: DrawerProps) {
  const {
    isOpen,
    onClose,
    position = "right",
    title,
    children,
    actions,
    dismissible = true,
    closeLabel = "Close drawer",
    ariaLabel = "Drawer",
    width,
    height,
    closeOnOutsideClick = true,
    closeOnEscape = true,
    portal = true,
    container,
    zIndex,
    blur,
    backgroundOpacity,
    animationDuration,
    easing,
    initialFocusRef,
    backdrop,
    headers,
    className,
    style,
  } = props;

  const reactId = useId();
  const titleId = `oks-drawer-title-${reactId.replace(/[:]/g, "")}`;
  const panelRef = useRef<HTMLDivElement | null>(null);
  const lastFocusedRef = useRef<Element | null>(null);

  useEffect(() => {
    if (!isOpen) return;
    if (typeof document === "undefined") return;

    lastFocusedRef.current = document.activeElement;
    let cancelled = false;

    const tryFocus = () => {
      if (cancelled) return;
      const target = initialFocusRef?.current ?? panelRef.current;
      if (target) {
        target.focus?.();
        return;
      }
      if (typeof window !== "undefined") window.requestAnimationFrame(tryFocus);
    };

    tryFocus();

    return () => {
      cancelled = true;
      const prev = lastFocusedRef.current;
      if (prev instanceof HTMLElement && document.contains(prev)) prev.focus();
    };
  }, [initialFocusRef, isOpen]);

  const resolvedWidth = useMemo(() => resolveWidth(width), [width]);
  const resolvedHeight = useMemo(() => resolveHeight(height), [height]);

  const cssVars: CSSProperties = useMemo(() => {
    return {
      ["--oks-drawer-width" as any]: resolvedWidth,
      ["--oks-drawer-height" as any]: resolvedHeight,
    } as CSSProperties;
  }, [resolvedHeight, resolvedWidth]);

  const panelStyle: CSSProperties = {
    ...cssVars,
    ...(style ?? {}),
  };

  const safeBackdropOverrides = useMemo(() => {
    if (!backdrop) return {};
    const {
      isOpen: _isOpen,
      onClose: _onClose,
      children: _children,
      ...rest
    } = backdrop as any;
    return rest as Omit<
      Partial<BackdropProps>,
      "isOpen" | "onClose" | "children"
    >;
  }, [backdrop]);

  const mergedBackdrop = {
    closeOnOutsideClick,
    closeOnEscape,
    portal,
    ...(container !== undefined ? { container } : {}),
    ...(zIndex !== undefined ? { zIndex } : {}),
    ...(blur !== undefined ? { blur } : {}),
    ...(backgroundOpacity !== undefined ? { backgroundOpacity } : {}),
    ...(animationDuration !== undefined ? { animationDuration } : {}),
    ...(easing !== undefined ? { easing } : {}),
    animationType: resolveAnimationType(position),
    contentFullSize: true,
    contentClassName: "oksDrawerBackdropContent",
    ...safeBackdropOverrides,
  } satisfies Omit<BackdropProps, "isOpen" | "onClose" | "children">;

  const headerTitle = headers?.title ?? title;
  const { title: _headersTitle, ...restHeaders } = headers ?? {};
  const resolvedHeaders: PageTitleProps = {
    as: "h4",
    ...restHeaders,
    ...(headerTitle !== undefined && headerTitle !== null
      ? { title: <span id={titleId}>{headerTitle}</span> }
      : {}),
  };

  const hasHeader = dismissible || resolvedHeaders.title !== undefined;

  const ariaLabelledBy =
    headerTitle !== undefined && headerTitle !== null ? titleId : undefined;

  const panelAriaProps =
    ariaLabelledBy !== undefined
      ? { "aria-labelledby": ariaLabelledBy }
      : { "aria-label": ariaLabel };

  return (
    <Backdrop isOpen={isOpen} onClose={onClose} {...mergedBackdrop}>
      <div
        ref={panelRef}
        role="dialog"
        aria-modal="true"
        tabIndex={-1}
        data-position={position}
        className={mergeClassName("oksDrawer", className)}
        style={panelStyle}
        {...panelAriaProps}
      >
        {hasHeader ? (
          <div className="oksDrawerHeader">
            <div className="oksDrawerHeaderTitle">
              {resolvedHeaders.title !== undefined &&
              resolvedHeaders.title !== null ? (
                <PageTitle {...resolvedHeaders} />
              ) : null}
            </div>
            {dismissible ? (
              <CloseButton
                className="oksDrawerClose"
                ariaLabel={closeLabel}
                onClick={() => onClose?.()}
              />
            ) : null}
          </div>
        ) : null}
        <div className="oksDrawerBody">{children}</div>
        {actions !== undefined && actions !== null ? (
          <div className="oksDrawerFooter">{actions}</div>
        ) : null}
      </div>
    </Backdrop>
  );
}

export default Drawer;
