import { isValidElement, cloneElement } from "react";
import type { CSSProperties, ReactElement } from "react";

export type SlotProps = {
  children: ReactElement;
} & Record<string, unknown>;

function mergeProps(
  slotProps: Record<string, unknown>,
  childProps: Record<string, unknown>
): Record<string, unknown> {
  const merged: Record<string, unknown> = { ...slotProps, ...childProps };

  const slotClassName = slotProps.className;
  const childClassName = childProps.className;
  if (typeof slotClassName === "string" || typeof childClassName === "string") {
    merged.className = [slotClassName, childClassName].filter(Boolean).join(" ");
  }

  const slotStyle = slotProps.style as CSSProperties | undefined;
  const childStyle = childProps.style as CSSProperties | undefined;
  if (slotStyle || childStyle) {
    merged.style = { ...slotStyle, ...childStyle };
  }

  for (const key of Object.keys(slotProps)) {
    if (!key.startsWith("on")) continue;
    const a = slotProps[key];
    const b = childProps[key];
    if (typeof a === "function" && typeof b === "function") {
      merged[key] = (...args: unknown[]) => {
        a(...args);
        b(...args);
      };
    }
  }

  return merged;
}

export function Slot({ children, ...slotProps }: SlotProps) {
  if (!isValidElement(children)) return null;
  const mergedProps = mergeProps(slotProps, children.props as Record<string, unknown>);
  return cloneElement(children, mergedProps);
}
