import type { CSSProperties, ReactNode } from "react";
import React, { useEffect, useMemo, useRef, useState } from "react";
import { useReducedMotion } from "../../motion";
import { Portal } from "../../primitives";
import "./Backdrop.module.css";

export type BackdropAnimationType =
  | "fade"
  | "zoom"
  | "slideUp"
  | "slideDown"
  | "slideLeft"
  | "slideRight";

export type BackdropEasing = "ease" | "easeIn" | "easeOut" | "easeInOut";

export type BackdropProps = {
  isOpen: boolean;
  onClose: () => void;
  children?: ReactNode;
  zIndex?: number;
  closeOnOutsideClick?: boolean;
  closeOnEscape?: boolean;
  lockScroll?: boolean;
  blur?: boolean;
  backgroundColor?: string;
  backgroundOpacity?: number;
  animationDuration?: number;
  animationType?: BackdropAnimationType;
  easing?: BackdropEasing;
  portal?: boolean;
  container?: Element | DocumentFragment | null;
  className?: string;
  style?: CSSProperties;
  contentFullSize?: boolean;
  contentClassName?: string;
  contentStyle?: CSSProperties;
};

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

let scrollLockCount = 0;
let prevDocumentOverflow: string | null = null;

function lockDocumentScroll() {
  if (typeof document === "undefined") return () => {};

  const el = document.documentElement;
  scrollLockCount += 1;
  if (scrollLockCount === 1) {
    prevDocumentOverflow = el.style.overflow;
    el.style.overflow = "hidden";
  }

  return () => {
    if (typeof document === "undefined") return;
    const el = document.documentElement;
    scrollLockCount = Math.max(0, scrollLockCount - 1);
    if (scrollLockCount === 0) {
      if (prevDocumentOverflow) {
        el.style.overflow = prevDocumentOverflow;
      } else {
        el.style.removeProperty("overflow");
      }
      prevDocumentOverflow = null;
    }
  };
}

function clampNumber(value: unknown, min: number, max: number) {
  const n = typeof value === "number" && Number.isFinite(value) ? value : min;
  return Math.min(max, Math.max(min, n));
}

function easingToCss(easing: BackdropEasing): string {
  if (easing === "easeIn") return "ease-in";
  if (easing === "easeOut") return "ease-out";
  if (easing === "easeInOut") return "ease-in-out";
  return "ease";
}

export function Backdrop(props: BackdropProps) {
  const {
    isOpen,
    onClose,
    children,
    zIndex = 40,
    closeOnOutsideClick = true,
    closeOnEscape = true,
    lockScroll = true,
    blur = true,
    backgroundColor = "var(--oks-palette-neutral-950, #000)",
    backgroundOpacity = 80,
    animationDuration = 0.3,
    animationType = "fade",
    easing = "ease",
    portal = true,
    container,
    className,
    style,
    contentFullSize = false,
    contentClassName,
    contentStyle,
  } = props;

  const reducedMotion = useReducedMotion();
  const [present, setPresent] = useState<boolean>(isOpen);
  const [backdropState, setBackdropState] = useState<"open" | "closed">(
    "closed",
  );
  const [contentState, setContentState] = useState<"open" | "closed">("closed");

  const timersRef = useRef<{
    openContent?: number;
    closeBackdrop?: number;
    unmount?: number;
    raf?: number;
  }>({});

  const durationMs = useMemo(() => {
    if (reducedMotion) return 0;
    return Math.round(clampNumber(animationDuration, 0, 10) * 1000);
  }, [animationDuration, reducedMotion]);

  const opacityVar = useMemo(() => {
    const clamped = clampNumber(backgroundOpacity, 0, 100);
    return String(clamped / 100);
  }, [backgroundOpacity]);

  const rootStyle = useMemo(() => {
    return {
      zIndex,
      ...style,
      ["--oks-backdrop-duration" as any]: `${durationMs}ms`,
      ["--oks-backdrop-easing" as any]: easingToCss(easing),
      ["--oks-backdrop-opacity" as any]: opacityVar,
    } as CSSProperties;
  }, [durationMs, easing, opacityVar, style, zIndex]);

  useEffect(() => {
    if (!lockScroll) return;
    if (!present) return;
    return lockDocumentScroll();
  }, [lockScroll, present]);

  useEffect(() => {
    if (!isOpen) return;
    if (!closeOnEscape) return;
    if (typeof document === "undefined") return;

    const onKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") onClose();
    };

    document.addEventListener("keydown", onKeyDown);
    return () => document.removeEventListener("keydown", onKeyDown);
  }, [closeOnEscape, isOpen, onClose]);

  useEffect(() => {
    const t = timersRef.current;
    if (typeof window !== "undefined") {
      if (t.openContent !== undefined) window.clearTimeout(t.openContent);
      if (t.closeBackdrop !== undefined) window.clearTimeout(t.closeBackdrop);
      if (t.unmount !== undefined) window.clearTimeout(t.unmount);
    }
    if (t.raf !== undefined && typeof window !== "undefined") {
      window.cancelAnimationFrame(t.raf);
    }
    timersRef.current = {};
  }, [durationMs]);

  useEffect(() => {
    const next: typeof timersRef.current = {};

    if (reducedMotion) {
      setPresent(isOpen);
      setBackdropState(isOpen ? "open" : "closed");
      setContentState(isOpen ? "open" : "closed");
      return;
    }

    if (typeof window === "undefined") {
      setPresent(isOpen);
      setBackdropState(isOpen ? "open" : "closed");
      setContentState(isOpen ? "open" : "closed");
      return;
    }

    if (isOpen) {
      setPresent(true);
      setBackdropState("closed");
      setContentState("closed");
      next.raf = window.requestAnimationFrame(() => setBackdropState("open"));
      next.openContent = window.setTimeout(
        () => setContentState("open"),
        durationMs,
      );
    } else {
      setContentState("closed");
      next.closeBackdrop = window.setTimeout(
        () => setBackdropState("closed"),
        durationMs,
      );
      next.unmount = window.setTimeout(() => setPresent(false), durationMs * 2);
    }

    timersRef.current = next;
    return () => {
      if (typeof window === "undefined") return;
      if (next.openContent !== undefined) window.clearTimeout(next.openContent);
      if (next.closeBackdrop !== undefined)
        window.clearTimeout(next.closeBackdrop);
      if (next.unmount !== undefined) window.clearTimeout(next.unmount);
      if (next.raf !== undefined) window.cancelAnimationFrame(next.raf);
    };
  }, [durationMs, isOpen, reducedMotion]);

  const overlay = (
    <div
      className="oksBackdropOverlay"
      data-blur={blur ? "true" : "false"}
      style={{ backgroundColor }}
      onPointerDown={closeOnOutsideClick ? onClose : undefined}
      aria-hidden="true"
    />
  );

  const content =
    children !== undefined && children !== null ? (
      <div
        className={mergeClassName("oksBackdropContent", contentClassName)}
        style={contentStyle}
      >
        {children}
      </div>
    ) : null;

  const root = present ? (
    <div
      className={mergeClassName("oksBackdrop", className)}
      style={rootStyle}
      data-state={backdropState}
      data-content-state={contentState}
      data-animation={animationType}
      data-motion={reducedMotion ? "reduced" : "full"}
      data-content-size={contentFullSize ? "full" : "auto"}
    >
      {overlay}
      {content}
    </div>
  ) : null;

  if (!portal) return root;
  return <Portal container={container}>{root}</Portal>;
}
