import type { ButtonHTMLAttributes, ReactNode } from "react";
import { cloneElement, forwardRef, isValidElement } from "react";
import { CloseIcon } from "../icons/StatusIcons";

function mergeClassName(a: unknown, b: unknown) {
  const sa = typeof a === "string" ? a : "";
  const sb = typeof b === "string" ? b : "";
  return [sa, sb].filter(Boolean).join(" ");
}

export type CloseButtonProps = Omit<
  ButtonHTMLAttributes<HTMLButtonElement>,
  "type" | "children" | "aria-label"
> & {
  ariaLabel: string;
  iconSize?: number;
  icon?: ReactNode;
  iconClassName?: string;
};

export const CloseButton = forwardRef<HTMLButtonElement, CloseButtonProps>(
  ({ ariaLabel, iconSize = 16, icon, iconClassName, ...rest }, ref) => {
    const resolvedIcon = (() => {
      if (icon === undefined) return <CloseIcon size={iconSize} className={iconClassName} />;
      if (!iconClassName) return icon;
      if (isValidElement(icon))
        return cloneElement(icon, {
          className: mergeClassName((icon.props as any).className, iconClassName),
        } as any);
      return <span className={iconClassName}>{icon}</span>;
    })();
    return (
      <button ref={ref} type="button" aria-label={ariaLabel} {...rest}>
        {resolvedIcon}
      </button>
    );
  },
);

CloseButton.displayName = "CloseButton";
