export const OKS_COLOR_SHADES = [50, 100, 200, 300, 400, 500, 600, 700, 800, 900, 950] as const;

export type OksColorShade = (typeof OKS_COLOR_SHADES)[number];

export function oksPaletteVarName(palette: string, shade: OksColorShade): string {
  return `oks-palette-${palette}-${shade}`;
}

export function oksColorVarName(role: string, shade: OksColorShade): string {
  return `oks-color-${role}-${shade}`;
}
