import { forwardRef, useCallback, useEffect, useId, useMemo, useState } from "react";
import type { ReactNode, Ref } from "react";
import { TabsContext, type TabsValue } from "./context";
import "./Tabs.module.css";

export type TabsRootProps = {
  id?: string;
  value?: TabsValue;
  defaultValue?: TabsValue;
  onChange?: (v: TabsValue) => void;
  mode?: "basic" | "url";
  tabId?: string;
  orientation?: "horizontal" | "vertical";
  tablistPosition?: "start" | "end";
  variant?: "underlineThick" | "segmented" | "pill" | "dot" | "outline";
  size?: "comfortable" | "compact";
  radius?: "none" | "sm" | "md" | "lg" | "full" | number;
  renderLazy?: boolean;
  children?: ReactNode;
  className?: string;
};

function toIdPart(value: unknown) {
  const str = String(value);
  return str
    .trim()
    .replace(/\s+/g, "-")
    .replace(/[^a-zA-Z0-9\-_:.]/g, "");
}

function isBrowser() {
  return typeof window !== "undefined" && typeof document !== "undefined";
}

function useURLParam(key?: string) {
  const get = useCallback((): string | null => {
    if (!isBrowser() || !key) return null;
    const url = new URL(window.location.href);
    return url.searchParams.get(key);
  }, [key]);
  const set = useCallback(
    (value?: string | null) => {
      if (!isBrowser() || !key) return;
      const url = new URL(window.location.href);
      const params = url.searchParams;
      if (value === undefined || value === null || value === "") {
        params.delete(key);
      } else {
        params.set(key, value);
      }
      const next = `${url.pathname}?${params.toString()}${url.hash ?? ""}`;
      window.history.pushState({}, "", next);
      const evt = new PopStateEvent("popstate");
      window.dispatchEvent(evt);
    },
    [key],
  );
  const subscribe = useCallback(
    (cb: (val: string | null) => void) => {
      if (!isBrowser() || !key) return () => {};
      const handler = () => cb(get());
      window.addEventListener("popstate", handler);
      return () => window.removeEventListener("popstate", handler);
    },
    [get, key],
  );
  return { get, set, subscribe };
}

export const TabsRoot = forwardRef<HTMLDivElement, TabsRootProps>(
  function TabsRoot(props, ref: Ref<HTMLDivElement>) {
    const {
      id,
      value,
      defaultValue,
      onChange,
      mode = "basic",
      tabId = "tab",
      orientation = "horizontal",
      tablistPosition = "start",
      variant,
      size = "comfortable",
      radius,
      renderLazy = true,
      className,
      children,
    } = props;

    const url = useURLParam(mode === "url" ? tabId : undefined);

    const initial = useMemo<TabsValue | undefined>(() => {
      if (mode === "url") {
        const u = url.get();
        if (u !== null) return u;
      }
      return defaultValue;
    }, [defaultValue, mode, url]);

    const controlled = value !== undefined;
    const [internal, setInternal] = useState<TabsValue | undefined>(initial);
    const current = controlled ? (value as TabsValue) : (internal as TabsValue);

    useEffect(() => {
      if (mode !== "url") return;
      const unsub = url.subscribe((val) => {
        if (val !== null) {
          if (!controlled) setInternal(val);
          onChange?.(val);
        }
      });
      return unsub;
    }, [controlled, mode, onChange, url]);

    const setValue = useCallback(
      (v: TabsValue) => {
        if (!controlled) setInternal(v);
        onChange?.(v);
        if (mode === "url") url.set(String(v));
      },
      [controlled, mode, onChange, url],
    );

    const autoId = useId();
    const idsBase = useMemo(() => {
      const base = id ? toIdPart(id) : toIdPart(`tabs-${autoId}`);
      return `oks-${base}`;
    }, [autoId, id]);

    const getIds = useCallback(
      (v: TabsValue) => {
        const part = toIdPart(v);
        return { tab: `${idsBase}-tab-${part}`, panel: `${idsBase}-panel-${part}` };
      },
      [idsBase],
    );

    const ctx = useMemo(() => {
      // Resolve variant to base appearance + defaults
      let resolvedAppearance:
        | "underline"
        | "segmented"
        | "pill"
        | "outline"
        | "dot" = "underline";
      let resolvedIndicator:
        | { height?: number | string; color?: string; glow?: boolean }
        | undefined = { height: 4 };
      let resolvedOptions:
        | {
            underline?: {
              position?: "bottom" | "top";
              cap?: "square" | "round";
              offset?: number;
              widthStrategy?: "tab" | "label";
            };
            pill?: { elevated?: boolean };
            outline?: { activeEmphasis?: "stroke" | "fill" };
          }
        | undefined = { underline: { widthStrategy: "tab" } };
      const v = variant;
      if (v) {
        if (v === "underlineThick") resolvedAppearance = "underline";
        if (v === "segmented") resolvedAppearance = "segmented";
        if (v === "pill") resolvedAppearance = "pill";
        if (v === "dot") resolvedAppearance = "dot";
        if (v === "outline") resolvedAppearance = "outline";
        if (v === "underlineThick") {
          resolvedIndicator = { height: 4 };
          resolvedOptions = { underline: { widthStrategy: "tab" } };
        } else if (v === "outline") {
          resolvedOptions = { outline: { activeEmphasis: "stroke" } };
        }
      }
      return {
        value: current,
        setValue,
        orientation,
        appearance: resolvedAppearance,
        density: size,
        radius,
        indicator: resolvedIndicator,
        appearanceOptions: resolvedOptions,
        renderLazy,
        getIds,
        isActive: (v: TabsValue) => v === current,
      };
    }, [
      variant,
      size,
      current,
      getIds,
      orientation,
      radius,
      renderLazy,
      setValue,
    ]);

    const rootClass = ["oksTabsRoot", className].filter(Boolean).join(" ");

    return (
      <TabsContext.Provider value={ctx}>
        <div
          ref={ref}
          id={id}
          className={rootClass}
          data-orientation={orientation}
          data-tablist-position={tablistPosition}
          data-density={size}
          data-underline-position={
            ctx.appearanceOptions?.underline?.position === "top"
              ? "top"
              : undefined
          }
          style={{
            ...(radius !== undefined
              ? {
                  ["--oks-tabs-radius" as any]:
                    typeof radius === "number"
                      ? `${radius}px`
                      : radius === "none"
                        ? "0px"
                        : radius === "sm"
                          ? "0.25rem"
                          : radius === "md"
                            ? "0.5rem"
                            : radius === "lg"
                              ? "0.75rem"
                              : radius === "full"
                                ? "9999px"
                                : undefined,
                }
              : undefined),
          }}
        >
          {children}
        </div>
      </TabsContext.Provider>
    );
  },
);

TabsRoot.displayName = "TabsRoot";
